// src/api-runner.ts
function chatCompletionsUrl(baseUrl) {
  return `${baseUrl.trim().replace(/\/+$/, "")}/chat/completions`;
}
function modelsUrl(baseUrl) {
  return `${baseUrl.trim().replace(/\/+$/, "")}/models`;
}
function buildChatBody(model, prompt) {
  return JSON.stringify({
    model: model.trim(),
    messages: [{ role: "user", content: prompt }],
    temperature: 0.2,
    stream: false
  });
}
function buildChatMessagesBody(model, messages) {
  return JSON.stringify({
    model: model.trim(),
    messages: messages.map((m) => ({ role: m.role, content: m.content })),
    temperature: 0.3,
    stream: false
  });
}
function extractApiReviewText(responseText) {
  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch {
    return "";
  }
  const choices = parsed.choices;
  if (!Array.isArray(choices) || choices.length === 0) return "";
  const message = choices[0].message;
  const content = message?.content;
  return typeof content === "string" ? content.trim() : "";
}
function extractApiError(responseText) {
  try {
    const parsed = JSON.parse(responseText);
    const err = parsed.error;
    if (typeof err === "string" && err) return err;
    if (err && typeof err === "object" && typeof err.message === "string") {
      return err.message;
    }
    if (typeof parsed.message === "string" && parsed.message) {
      return parsed.message;
    }
  } catch {
  }
  const trimmed = responseText.trim();
  return trimmed.length > 200 ? `${trimmed.slice(0, 197)}\u2026` : trimmed;
}
function extractApiModels(responseText) {
  try {
    const parsed = JSON.parse(responseText);
    if (!Array.isArray(parsed.data)) return [];
    return parsed.data.map((item) => typeof item.id === "string" ? item.id : "").filter(Boolean);
  } catch {
    return [];
  }
}
async function runApiReview(opts, request) {
  if (!opts.apiKey.trim()) {
    return { ok: false, reviewText: "", error: "missing-api-key" };
  }
  let response;
  try {
    response = await request({
      url: chatCompletionsUrl(opts.baseUrl),
      method: "POST",
      headers: {
        "Content-Type": "application/json; charset=utf-8",
        Authorization: `Bearer ${opts.apiKey.trim()}`
      },
      body: buildChatBody(opts.model, opts.prompt),
      timeoutMs: opts.timeoutMs
    });
  } catch (error51) {
    const message = error51 instanceof Error ? error51.message : String(error51);
    return {
      ok: false,
      reviewText: "",
      timedOut: /tim(?:e|ed)?\s?-?\s?out/i.test(message),
      error: message
    };
  }
  if (response.status < 200 || response.status >= 300) {
    return {
      ok: false,
      reviewText: "",
      status: response.status,
      error: extractApiError(response.text)
    };
  }
  return {
    ok: true,
    reviewText: extractApiReviewText(response.text),
    status: response.status
  };
}
async function runApiChat(opts, request) {
  if (!opts.apiKey.trim()) {
    return { ok: false, reviewText: "", error: "missing-api-key" };
  }
  let response;
  try {
    response = await request({
      url: chatCompletionsUrl(opts.baseUrl),
      method: "POST",
      headers: {
        "Content-Type": "application/json; charset=utf-8",
        Authorization: `Bearer ${opts.apiKey.trim()}`
      },
      body: buildChatMessagesBody(opts.model, opts.messages),
      timeoutMs: opts.timeoutMs
    });
  } catch (error51) {
    const message = error51 instanceof Error ? error51.message : String(error51);
    return {
      ok: false,
      reviewText: "",
      timedOut: /tim(?:e|ed)?\s?-?\s?out/i.test(message),
      error: message
    };
  }
  if (response.status < 200 || response.status >= 300) {
    return {
      ok: false,
      reviewText: "",
      status: response.status,
      error: extractApiError(response.text)
    };
  }
  return {
    ok: true,
    reviewText: extractApiReviewText(response.text),
    status: response.status
  };
}
function pickApiModel(models, current2) {
  if (current2 && models.includes(current2)) return current2;
  return models.find((id) => /flash/i.test(id)) ?? models.find((id) => /chat/i.test(id)) ?? models[0] ?? current2;
}
async function listApiModels(opts, request) {
  if (!opts.apiKey.trim()) {
    return { ok: false, models: [], error: "missing-api-key" };
  }
  let response;
  try {
    response = await request({
      url: modelsUrl(opts.baseUrl),
      method: "GET",
      headers: { Authorization: `Bearer ${opts.apiKey.trim()}` },
      timeoutMs: opts.timeoutMs
    });
  } catch (error51) {
    return {
      ok: false,
      models: [],
      error: error51 instanceof Error ? error51.message : String(error51)
    };
  }
  if (response.status < 200 || response.status >= 300) {
    return {
      ok: false,
      models: [],
      status: response.status,
      error: extractApiError(response.text)
    };
  }
  return { ok: true, models: extractApiModels(response.text), status: response.status };
}

// src/store.ts
var import_obsidian = require("obsidian");

// src/learning.ts
function isStrength(cell) {
  return cell.type === "understanding" || cell.type === "strategy" || cell.status === "stable" || cell.confidence >= 0.8;
}
function isWeakness(cell) {
  return cell.type === "misconception" || cell.type === "difficulty" || cell.status === "needs_review" || cell.confidence < 0.5;
}
function classifyCells(cells) {
  const strengths = [];
  const weaknesses = [];
  const methods = [];
  for (const cell of cells) {
    if (cell.type === "strategy") methods.push(cell);
    if (isWeakness(cell)) weaknesses.push(cell);
    else if (isStrength(cell)) strengths.push(cell);
  }
  weaknesses.sort((a, b) => a.confidence - b.confidence || a.id.localeCompare(b.id));
  strengths.sort((a, b) => b.confidence - a.confidence || a.id.localeCompare(b.id));
  methods.sort((a, b) => b.updatedAt.localeCompare(a.updatedAt) || a.id.localeCompare(b.id));
  return { strengths, weaknesses, methods };
}

